import { BundleAdapter } from './coding';

describe('BundleAdapter', () => {
  let bundle: BundleAdapter;

  beforeEach(() => {
    bundle = new BundleAdapter();
  });

  describe('Basic Operations', () => {
    test('should create empty bundle', () => {
      expect(bundle.isEmpty()).toBe(true);
      expect(bundle.size()).toBe(0);
    });

    test('should put and get string value', () => {
      bundle.put('name', 'John');
      expect(bundle.getString('name')).toBe('John');
    });

    test('should put and get integer value', () => {
      bundle.put('age', 25);
      expect(bundle.getInt('age')).toBe(25);
    });

    test('should put and get boolean value', () => {
      bundle.put('active', true);
      expect(bundle.getBoolean('active')).toBe(true);
    });
  });

  describe('Default Values', () => {
    test('should return default string when key missing', () => {
      expect(bundle.getString('missing', 'default')).toBe('default');
    });

    test('should return default int when key missing', () => {
      expect(bundle.getInt('missing', 42)).toBe(42);
    });

    test('should return default boolean when key missing', () => {
      expect(bundle.getBoolean('missing', true)).toBe(true);
    });

    test('should return undefined when no default provided', () => {
      expect(bundle.getString('missing')).toBeUndefined();
      expect(bundle.getInt('missing')).toBeUndefined();
      expect(bundle.getBoolean('missing')).toBeUndefined();
    });
  });

  describe('Type Conversion', () => {
    test('should convert number to string', () => {
      bundle.put('count', 42);
      expect(bundle.getString('count')).toBe('42');
    });

    test('should convert string to int', () => {
      bundle.put('count', '42');
      expect(bundle.getInt('count')).toBe(42);
    });

    test('should convert string to boolean', () => {
      bundle.put('flag', 'true');
      expect(bundle.getBoolean('flag')).toBe(true);
    });
  });

  describe('Key Management', () => {
    test('should check key existence', () => {
      bundle.put('key', 'value');
      expect(bundle.containsKey('key')).toBe(true);
      expect(bundle.containsKey('missing')).toBe(false);
    });

    test('should return all keys', () => {
      bundle.put('a', 1);
      bundle.put('b', 2);
      bundle.put('c', 3);
      expect(bundle.keySet()).toEqual(['a', 'b', 'c']);
    });

    test('should remove key', () => {
      bundle.put('key', 'value');
      bundle.remove('key');
      expect(bundle.containsKey('key')).toBe(false);
    });

    test('should clear all data', () => {
      bundle.put('a', 1);
      bundle.put('b', 2);
      bundle.clear();
      expect(bundle.isEmpty()).toBe(true);
    });
  });

  describe('Clone', () => {
    test('should clone bundle', () => {
      bundle.put('name', 'John');
      bundle.put('age', 25);
      
      const cloned = bundle.clone();
      
      expect(cloned.getString('name')).toBe('John');
      expect(cloned.getInt('age')).toBe(25);
    });

    test('cloned bundle should be independent', () => {
      bundle.put('key', 'original');
      const cloned = bundle.clone();
      
      bundle.put('key', 'modified');
      
      expect(cloned.getString('key')).toBe('original');
    });
  });

  describe('toWantParams', () => {
    test('should convert to wantParams', () => {
      bundle.put('name', 'John');
      bundle.put('age', 25);
      
      const params = bundle.toWantParams();
      
      expect(params).toEqual({
        name: 'John',
        age: 25
      });
    });

    test('should create from wantParams', () => {
      const params = { name: 'Jane', score: 100 };
      const fromParams = BundleAdapter.fromWantParams(params);
      
      expect(fromParams.getString('name')).toBe('Jane');
      expect(fromParams.getInt('score')).toBe(100);
    });
  });

  describe('Edge Cases', () => {
    test('should handle empty string', () => {
      bundle.put('empty', '');
      expect(bundle.getString('empty')).toBe('');
    });

    test('should handle zero', () => {
      bundle.put('zero', 0);
      expect(bundle.getInt('zero')).toBe(0);
    });

    test('should handle false boolean', () => {
      bundle.put('false', false);
      expect(bundle.getBoolean('false')).toBe(false);
    });

    test('should handle null', () => {
      bundle.put('null', null);
      expect(bundle.get('null')).toBeNull();
    });

    test('should handle undefined', () => {
      bundle.put('undefined', undefined);
      expect(bundle.get('undefined')).toBeUndefined();
    });
  });

  describe('Complex Objects', () => {
    test('should store and retrieve objects', () => {
      const obj = { nested: { value: 42 } };
      bundle.put('complex', obj);
      expect(bundle.get('complex')).toEqual(obj);
    });

    test('should store arrays', () => {
      const arr = [1, 2, 3];
      bundle.put('array', arr);
      expect(bundle.get('array')).toEqual(arr);
    });
  });
});

